"use client";

import { memo, useEffect, useImperativeHandle, useMemo, useRef } from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_ENGAGEMENT_BAR_LABELS,
  type EngagementAction,
  type EngagementActionAlign,
  type EngagementBar01Handle,
  type EngagementBar01Props,
  type EngagementBarLabels,
  type EngagementState,
} from "./types";
import { ActionButton } from "./parts/action-button";
import {
  deriveStateFromActions,
  useEngagementState,
} from "./hooks/use-engagement-state";
import { formatEngagementCount } from "./lib/format-count";

interface EngagementBar01InnerProps extends EngagementBar01Props {
  ref?: React.Ref<EngagementBar01Handle>;
}

function defaultAlignFor(kind: EngagementAction["kind"]): EngagementActionAlign {
  return kind === "bookmark" || kind === "view-count" ? "right" : "left";
}

function actionKey(action: EngagementAction, index: number): string {
  if (action.kind === "custom") return `custom-${action.id}`;
  return `${action.kind}-${index}`;
}

function EngagementBar01Inner({
  actions,
  variant = "default",
  subscribe,
  onSubscribeDelta,
  likersPreview,
  labels: labelsProp,
  className,
  actionClassName,
  ref,
}: EngagementBar01InnerProps) {
  const { state, dispatch, controlled } = useEngagementState({
    actions,
    subscribe,
    onSubscribeDelta,
  });

  const labels = useMemo<Required<Omit<EngagementBarLabels, "formatCount">>>(
    () => ({ ...DEFAULT_ENGAGEMENT_BAR_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const format = useMemo<(n: number) => string>(
    () => labelsProp?.formatCount ?? formatEngagementCount,
    [labelsProp?.formatCount],
  );

  // Stable handle identity — refs mirror state + actions via passive effect
  // (refs must not be written during render).
  const stateRef = useRef<EngagementState>(state);
  const actionsRef = useRef<EngagementAction[]>(actions);
  useEffect(() => {
    stateRef.current = state;
    actionsRef.current = actions;
  });

  useImperativeHandle(
    ref,
    () => ({
      triggerLike: () => {
        const likeAction = actionsRef.current.find((a) => a.kind === "like");
        if (!likeAction || likeAction.kind !== "like") return;
        const next = !stateRef.current.liked;
        if (likeAction.liked === undefined) {
          dispatch({ kind: "like-toggle" });
        }
        likeAction.onToggle?.(next);
      },
      triggerBookmark: () => {
        const bookmarkAction = actionsRef.current.find(
          (a) => a.kind === "bookmark",
        );
        if (!bookmarkAction || bookmarkAction.kind !== "bookmark") return;
        const next = !stateRef.current.bookmarked;
        if (bookmarkAction.bookmarked === undefined) {
          dispatch({ kind: "bookmark-toggle" });
        }
        bookmarkAction.onToggle?.(next);
      },
      getCurrentState: () => stateRef.current,
      reset: () => {
        dispatch({
          kind: "reset",
          next: deriveStateFromActions(actionsRef.current),
        });
      },
    }),
    // dispatch is stable; refs handle the rest. Empty dep array → handle identity is stable.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  if (actions.length === 0) return null;

  // Stacked variant: vertical list, no left/right split, align ignored.
  if (variant === "stacked") {
    return (
      <div
        className={cn("flex flex-col items-center gap-3", className)}
      >
        {actions.map((action, index) => (
          <ActionButton
            key={actionKey(action, index)}
            action={action}
            variant={variant}
            state={state}
            controlled={controlled}
            dispatch={dispatch}
            format={format}
            labels={labels}
            actionClassName={actionClassName}
          />
        ))}
        {likersPreview ? <div className="mt-1">{likersPreview}</div> : null}
      </div>
    );
  }

  // Default + compact: horizontal row split by align.
  const leftActions: EngagementAction[] = [];
  const rightActions: EngagementAction[] = [];
  for (const action of actions) {
    const align = action.align ?? defaultAlignFor(action.kind);
    if (align === "right") rightActions.push(action);
    else leftActions.push(action);
  }

  const outerGapClass = variant === "compact" ? "gap-1" : "gap-2";

  return (
    <div className={cn("flex flex-col", outerGapClass, className)}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-1">
          {leftActions.map((action, index) => (
            <ActionButton
              key={actionKey(action, index)}
              action={action}
              variant={variant}
              state={state}
              controlled={controlled}
              dispatch={dispatch}
              format={format}
              labels={labels}
              actionClassName={actionClassName}
            />
          ))}
        </div>
        {rightActions.length > 0 ? (
          <div className="flex items-center gap-1">
            {rightActions.map((action, index) => (
              <ActionButton
                key={actionKey(action, index)}
                action={action}
                variant={variant}
                state={state}
                controlled={controlled}
                dispatch={dispatch}
                format={format}
                labels={labels}
                actionClassName={actionClassName}
              />
            ))}
          </div>
        ) : null}
      </div>
      {likersPreview ? <div className="mt-1">{likersPreview}</div> : null}
    </div>
  );
}

const EngagementBar01 = memo(EngagementBar01Inner);
EngagementBar01.displayName = "EngagementBar01";

export { EngagementBar01 };

export { EngagementBar01 } from "./engagement-bar-01";
export { EngagementHeartBurst } from "./parts/engagement-heart-burst";
export type { EngagementHeartBurstProps } from "./parts/engagement-heart-burst";
export {
  engagementReducer,
  useEngagementState,
  deriveStateFromActions,
} from "./hooks/use-engagement-state";
export type {
  UseEngagementStateOptions,
  UseEngagementStateResult,
} from "./hooks/use-engagement-state";
export { formatEngagementCount } from "./lib/format-count";

export type {
  EngagementBar01Props,
  EngagementBar01Handle,
  EngagementBar01Variant,
  EngagementBarLabels,
  EngagementAction,
  EngagementActionAlign,
  EngagementDelta,
  EngagementLikeUser,
  EngagementState,
  EngagementLocalAction,
  Subscribe,
  Unsubscribe,
} from "./types";

export { DEFAULT_ENGAGEMENT_BAR_LABELS } from "./types";

import type { ReactNode } from "react";

export type EngagementBar01Variant = "default" | "compact" | "stacked";

export type EngagementActionAlign = "left" | "right" | "auto";

/** Strict discriminated union — no extra fields. */
export type EngagementAction =
  | {
      kind: "like";
      count: number;
      liked?: boolean;
      onToggle?: (next: boolean) => void;
      /**
       * Optional separate click target for the count number. When provided, the
       * like action splits into two clickable elements:
       *   - the heart icon (fires onToggle)
       *   - the count text (fires onCountClick)
       * Use this for kasder-style "tap heart to like, tap count to open likers panel".
       * If omitted, the heart + count behave as a single button (backwards-compatible).
       */
      onCountClick?: () => void;
      align?: EngagementActionAlign;
    }
  | {
      kind: "comment";
      count: number;
      onClick?: () => void;
      align?: EngagementActionAlign;
    }
  | {
      kind: "share";
      count?: number;
      onClick?: () => void;
      align?: EngagementActionAlign;
    }
  | {
      kind: "bookmark";
      bookmarked?: boolean;
      onToggle?: (next: boolean) => void;
      align?: EngagementActionAlign;
    }
  | {
      kind: "view-count";
      count: number;
      align?: EngagementActionAlign;
    }
  | {
      kind: "custom";
      id: string;
      label: string;
      icon: ReactNode;
      count?: number;
      active?: boolean;
      onClick?: () => void;
      align?: EngagementActionAlign;
    };

export interface EngagementLikeUser {
  id: string;
  name: string;
  username: string;
  avatar: string;
}

/** Realtime delta union. Same shape conventions as comment-thread-01 will use. */
export type EngagementDelta =
  | { kind: "like-changed"; count: number; liked?: boolean; userId?: string }
  | { kind: "comment-count-changed"; count: number }
  | { kind: "share-count-changed"; count: number }
  | { kind: "view-count-changed"; count: number }
  | { kind: "bookmark-changed"; bookmarked: boolean }
  | { kind: "liker-added"; user: EngagementLikeUser }
  | { kind: "liker-removed"; userId: string };

export type Unsubscribe = () => void;
export type Subscribe<T> = (handler: (delta: T) => void) => Unsubscribe;

export interface EngagementBarLabels {
  /** Default: "Like". aria-label when not liked. */
  like?: string;
  /** Default: "Unlike". aria-label when liked. */
  unlike?: string;
  /** Default: "Show likers". aria-label for the count-as-button when split via onCountClick. */
  openLikersPanel?: string;
  /** Default: "Comment". aria-label on comment action. */
  comment?: string;
  /** Default: "Share". aria-label on share action. */
  share?: string;
  /** Default: "Bookmark". aria-label when not bookmarked. */
  bookmark?: string;
  /** Default: "Remove bookmark". aria-label when bookmarked. */
  unbookmark?: string;
  /** Default: "Views". aria-label on view-count display. */
  viewCount?: string;
  /** Optional locale-aware count formatter. Defaults to formatEngagementCount. */
  formatCount?: (n: number) => string;
}

export interface EngagementBar01Props {
  /** The actions to render. Required. Order = render order (within each align group). */
  actions: EngagementAction[];
  /** Variant. Default: "default". */
  variant?: EngagementBar01Variant;
  /** Realtime subscription. Optional. Identity must be stable across renders (memoize via useCallback). */
  subscribe?: Subscribe<EngagementDelta>;
  /** Fires for every delta the subscription emits, regardless of controlled/uncontrolled mode. */
  onSubscribeDelta?: (delta: EngagementDelta) => void;
  /** Slot rendered below the action row. Hosts use for likers preview / "X liked this" / etc. */
  likersPreview?: ReactNode;
  /** Localized labels. Defaults are English. */
  labels?: EngagementBarLabels;
  /** Override classes for the wrapping <div>. */
  className?: string;
  /** Override classes for each action button. */
  actionClassName?: string;
}

export interface EngagementBar01Handle {
  /** Programmatically toggle the like action (flips state + fires onToggle). No-op if no like action present. */
  triggerLike: () => void;
  /** Programmatically toggle the bookmark action. No-op if no bookmark action present. */
  triggerBookmark: () => void;
  /** Read the current optimistic state of all toggleable actions. */
  getCurrentState: () => EngagementState;
  /** Reset internal optimistic state to actions' values (no-op for fully-controlled fields). */
  reset: () => void;
}

/** Internal optimistic state shape. Public-readable via getCurrentState() / engagementReducer. */
export interface EngagementState {
  liked: boolean;
  likeCount: number;
  commentCount: number;
  shareCount: number | null;
  viewCount: number | null;
  bookmarked: boolean;
}

/** Reducer action union. Public for hosts driving their own state machines. */
export type EngagementLocalAction =
  | { kind: "like-toggle" }
  | { kind: "bookmark-toggle" }
  | { kind: "subscribe-delta"; delta: EngagementDelta }
  | { kind: "reset"; next: EngagementState };

export const DEFAULT_ENGAGEMENT_BAR_LABELS: Required<
  Omit<EngagementBarLabels, "formatCount">
> = {
  like: "Like",
  unlike: "Unlike",
  openLikersPanel: "Show likers",
  comment: "Comment",
  share: "Share",
  bookmark: "Bookmark",
  unbookmark: "Remove bookmark",
  viewCount: "Views",
};

"use client";

import { memo } from "react";
import type {
  EngagementAction,
  EngagementBar01Variant,
  EngagementBarLabels,
  EngagementLocalAction,
  EngagementState,
} from "../types";
import { LikeAction } from "./like-action";
import { CommentAction } from "./comment-action";
import { ShareAction } from "./share-action";
import { BookmarkAction } from "./bookmark-action";
import { ViewCountAction } from "./view-count-action";
import { CustomAction } from "./custom-action";

interface ControlledFlags {
  liked: boolean;
  bookmarked: boolean;
}

interface ActionButtonProps {
  action: EngagementAction;
  variant: EngagementBar01Variant;
  state: EngagementState;
  controlled: ControlledFlags;
  dispatch: React.Dispatch<EngagementLocalAction>;
  format: (n: number) => string;
  labels: Required<Omit<EngagementBarLabels, "formatCount">>;
  actionClassName?: string;
}

/**
 * Dispatches to the per-kind action component. Click handlers live INSIDE
 * each per-kind component (not memoized upstream — that would be a hooks-rules
 * violation inside `.map()`). React.memo on each per-kind keeps re-renders cheap.
 */
function ActionButtonInner({
  action,
  variant,
  state,
  controlled,
  dispatch,
  format,
  labels,
  actionClassName,
}: ActionButtonProps) {
  switch (action.kind) {
    case "like":
      return (
        <LikeAction
          variant={variant}
          liked={state.liked}
          count={state.likeCount}
          controlled={controlled.liked}
          onToggle={action.onToggle}
          onCountClick={action.onCountClick}
          format={format}
          labels={labels}
          dispatch={dispatch}
          actionClassName={actionClassName}
        />
      );
    case "comment":
      return (
        <CommentAction
          variant={variant}
          count={state.commentCount}
          onClick={action.onClick}
          format={format}
          labels={labels}
          actionClassName={actionClassName}
        />
      );
    case "share":
      return (
        <ShareAction
          variant={variant}
          count={state.shareCount ?? undefined}
          onClick={action.onClick}
          format={format}
          labels={labels}
          actionClassName={actionClassName}
        />
      );
    case "bookmark":
      return (
        <BookmarkAction
          variant={variant}
          bookmarked={state.bookmarked}
          controlled={controlled.bookmarked}
          onToggle={action.onToggle}
          labels={labels}
          dispatch={dispatch}
          actionClassName={actionClassName}
        />
      );
    case "view-count":
      return (
        <ViewCountAction
          variant={variant}
          count={state.viewCount ?? action.count}
          format={format}
          labels={labels}
          actionClassName={actionClassName}
        />
      );
    case "custom":
      return (
        <CustomAction
          variant={variant}
          id={action.id}
          label={action.label}
          icon={action.icon}
          count={action.count}
          active={action.active}
          onClick={action.onClick}
          format={format}
          actionClassName={actionClassName}
        />
      );
  }
}

export const ActionButton = memo(ActionButtonInner);
ActionButton.displayName = "ActionButton";

"use client";

import { memo } from "react";
import { Heart } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type {
  EngagementBar01Variant,
  EngagementBarLabels,
  EngagementLocalAction,
} from "../types";

interface LikeActionProps {
  variant: EngagementBar01Variant;
  liked: boolean;
  count: number;
  controlled: boolean;
  onToggle?: (next: boolean) => void;
  /** When provided, count becomes a separate clickable target. */
  onCountClick?: () => void;
  format: (n: number) => string;
  labels: Required<Omit<EngagementBarLabels, "formatCount">>;
  dispatch: React.Dispatch<EngagementLocalAction>;
  actionClassName?: string;
}

function LikeActionInner({
  variant,
  liked,
  count,
  controlled,
  onToggle,
  onCountClick,
  format,
  labels,
  dispatch,
  actionClassName,
}: LikeActionProps) {
  const handleHeartClick = () => {
    const next = !liked;
    if (!controlled) {
      dispatch({ kind: "like-toggle" });
    }
    onToggle?.(next);
  };

  const heartAriaLabel = liked ? labels.unlike : labels.like;
  const iconSizeClass = variant === "compact" ? "h-4 w-4" : "h-5 w-5";
  const splitCount = !!onCountClick;

  if (variant === "stacked") {
    // Stacked layout: heart icon + count vertically. Split mode wraps each in
    // its own button.
    if (splitCount) {
      return (
        <div className={cn("flex flex-col items-center gap-0.5", actionClassName)}>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            aria-pressed={liked}
            aria-label={heartAriaLabel}
            onClick={handleHeartClick}
            className={cn("h-auto px-2 py-1", liked && "text-destructive")}
          >
            <Heart
              className={cn(
                "h-6 w-6 transition-transform",
                liked && "scale-110 fill-current",
              )}
            />
          </Button>
          <button
            type="button"
            onClick={onCountClick}
            aria-label={labels.openLikersPanel ?? "Show likers"}
            className="rounded text-xs font-medium tabular-nums text-foreground hover:underline focus:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          >
            {format(count)}
          </button>
        </div>
      );
    }
    return (
      <Button
        type="button"
        variant="ghost"
        size="sm"
        aria-pressed={liked}
        aria-label={heartAriaLabel}
        onClick={handleHeartClick}
        className={cn(
          "flex h-auto flex-col items-center gap-0.5 px-2 py-1",
          liked && "text-destructive",
          actionClassName,
        )}
      >
        <Heart
          className={cn(
            "h-6 w-6 transition-transform",
            liked && "scale-110 fill-current",
          )}
        />
        <span className="text-xs font-medium tabular-nums" aria-live="polite">
          {format(count)}
        </span>
      </Button>
    );
  }

  // Default + compact horizontal layout. Split mode: heart Button + count button
  // separated by gap-2 to visually match the bundled `gap-2 px-2` of single-button
  // actions (comment / share / bookmark / view-count).
  if (splitCount) {
    return (
      <div className={cn("flex items-center gap-2 pr-2", actionClassName)}>
        <Button
          type="button"
          variant="ghost"
          size="sm"
          aria-pressed={liked}
          aria-label={heartAriaLabel}
          onClick={handleHeartClick}
          className={cn(
            "h-9 px-2 transition-colors",
            liked && "text-destructive",
          )}
        >
          <Heart
            className={cn(
              iconSizeClass,
              "transition-transform",
              liked && "scale-110 fill-current",
            )}
          />
        </Button>
        <button
          type="button"
          onClick={onCountClick}
          aria-label={labels.openLikersPanel ?? "Show likers"}
          className={cn(
            "rounded text-sm font-medium tabular-nums transition-colors hover:underline focus:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            liked ? "text-destructive" : "text-foreground",
          )}
        >
          {format(count)}
        </button>
      </div>
    );
  }

  return (
    <Button
      type="button"
      variant="ghost"
      size="sm"
      aria-pressed={liked}
      aria-label={heartAriaLabel}
      onClick={handleHeartClick}
      className={cn(
        "gap-2 px-2 transition-colors",
        liked && "text-destructive",
        actionClassName,
      )}
    >
      <Heart
        className={cn(
          iconSizeClass,
          "transition-transform",
          liked && "scale-110 fill-current",
        )}
      />
      <span className="text-sm font-medium tabular-nums" aria-live="polite">
        {format(count)}
      </span>
    </Button>
  );
}

export const LikeAction = memo(LikeActionInner);
LikeAction.displayName = "LikeAction";

"use client";

import { memo } from "react";
import { MessageCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { EngagementBar01Variant, EngagementBarLabels } from "../types";

interface CommentActionProps {
  variant: EngagementBar01Variant;
  count: number;
  onClick?: () => void;
  format: (n: number) => string;
  labels: Required<Omit<EngagementBarLabels, "formatCount">>;
  actionClassName?: string;
}

function CommentActionInner({
  variant,
  count,
  onClick,
  format,
  labels,
  actionClassName,
}: CommentActionProps) {
  const iconSizeClass = variant === "compact" ? "h-4 w-4" : "h-5 w-5";

  if (variant === "stacked") {
    return (
      <Button
        type="button"
        variant="ghost"
        size="sm"
        aria-label={labels.comment}
        onClick={onClick}
        className={cn(
          "flex h-auto flex-col items-center gap-0.5 px-2 py-1",
          actionClassName,
        )}
      >
        <MessageCircle className="h-6 w-6" />
        <span className="text-xs font-medium tabular-nums">
          {format(count)}
        </span>
      </Button>
    );
  }

  return (
    <Button
      type="button"
      variant="ghost"
      size="sm"
      aria-label={labels.comment}
      onClick={onClick}
      className={cn("gap-2 px-2", actionClassName)}
    >
      <MessageCircle className={iconSizeClass} />
      <span className="text-sm font-medium tabular-nums">{format(count)}</span>
    </Button>
  );
}

export const CommentAction = memo(CommentActionInner);
CommentAction.displayName = "CommentAction";

"use client";

import { memo } from "react";
import { Share2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { EngagementBar01Variant, EngagementBarLabels } from "../types";

interface ShareActionProps {
  variant: EngagementBar01Variant;
  count?: number;
  onClick?: () => void;
  format: (n: number) => string;
  labels: Required<Omit<EngagementBarLabels, "formatCount">>;
  actionClassName?: string;
}

function ShareActionInner({
  variant,
  count,
  onClick,
  format,
  labels,
  actionClassName,
}: ShareActionProps) {
  const iconSizeClass = variant === "compact" ? "h-4 w-4" : "h-5 w-5";
  const showCount = count !== undefined;

  if (variant === "stacked") {
    return (
      <Button
        type="button"
        variant="ghost"
        size="sm"
        aria-label={labels.share}
        onClick={onClick}
        className={cn(
          "flex h-auto flex-col items-center gap-0.5 px-2 py-1",
          actionClassName,
        )}
      >
        <Share2 className="h-6 w-6" />
        {showCount ? (
          <span className="text-xs font-medium tabular-nums">
            {format(count)}
          </span>
        ) : null}
      </Button>
    );
  }

  return (
    <Button
      type="button"
      variant="ghost"
      size="sm"
      aria-label={labels.share}
      onClick={onClick}
      className={cn(showCount ? "gap-2 px-2" : "px-2", actionClassName)}
    >
      <Share2 className={iconSizeClass} />
      {showCount ? (
        <span className="text-sm font-medium tabular-nums">
          {format(count)}
        </span>
      ) : null}
    </Button>
  );
}

export const ShareAction = memo(ShareActionInner);
ShareAction.displayName = "ShareAction";

"use client";

import { memo } from "react";
import { Bookmark } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type {
  EngagementBar01Variant,
  EngagementBarLabels,
  EngagementLocalAction,
} from "../types";

interface BookmarkActionProps {
  variant: EngagementBar01Variant;
  bookmarked: boolean;
  controlled: boolean;
  onToggle?: (next: boolean) => void;
  labels: Required<Omit<EngagementBarLabels, "formatCount">>;
  dispatch: React.Dispatch<EngagementLocalAction>;
  actionClassName?: string;
}

function BookmarkActionInner({
  variant,
  bookmarked,
  controlled,
  onToggle,
  labels,
  dispatch,
  actionClassName,
}: BookmarkActionProps) {
  const handleClick = () => {
    const next = !bookmarked;
    if (!controlled) {
      dispatch({ kind: "bookmark-toggle" });
    }
    onToggle?.(next);
  };

  const ariaLabel = bookmarked ? labels.unbookmark : labels.bookmark;
  const iconSizeClass = variant === "compact" ? "h-4 w-4" : "h-5 w-5";

  if (variant === "stacked") {
    return (
      <Button
        type="button"
        variant="ghost"
        size="sm"
        aria-pressed={bookmarked}
        aria-label={ariaLabel}
        onClick={handleClick}
        className={cn(
          "flex h-auto flex-col items-center gap-0.5 px-2 py-1",
          actionClassName,
        )}
      >
        <Bookmark
          className={cn("h-6 w-6 transition-all", bookmarked && "fill-current")}
        />
      </Button>
    );
  }

  return (
    <Button
      type="button"
      variant="ghost"
      size="sm"
      aria-pressed={bookmarked}
      aria-label={ariaLabel}
      onClick={handleClick}
      className={cn("px-2 transition-colors", actionClassName)}
    >
      <Bookmark
        className={cn(
          iconSizeClass,
          "transition-all",
